{% if product.metafields.custom.fitting or product.metafields.custom.fitting_number %}
  {% if product.metafields.custom.fitting %}
    <p class="size-chart">{{ product.metafields.custom.fitting }}</p>
  {% endif %}

  {% if product.metafields.custom.fitting_number %}
    <div class="size-bar-container">
      <div class="size-bar">
        <div class="size-bar-marker"></div>
      </div>
      <p class="size-label left"></p>
      <p class="size-label right"></p>
    </div>

    <script>
      document.addEventListener("DOMContentLoaded", function() {
        let marker = document.querySelector('.size-bar-marker');
        let position = {{ product.metafields.custom.fitting_number | default: 50 }};
        marker.style.left = Math.min(Math.max(position, 1), 100) + "%";
      });
    </script>
  {% endif %}
{% endif %}

<style>
  .size-chart {
    font-size: 12px;
    color: #333;
    text-align: center;
    margin-top: 0px;
    margin-bottom: 0px;
  }

  .size-bar-container {
    position: relative;
    width: 100%;
    max-width: 80%;
    margin: 0px auto;
    text-align: center;
    padding-bottom: 10px;
  }

  .size-bar {
    position: relative;
    width: 100%;
    height: 10px;
    background: linear-gradient(to right, #3D6E2E, #85C1FF);
    border-radius: 50px;
    margin-top: 10px;
  }

  .size-bar-marker {
    position: absolute;
    top: 50%;
    transform: translateY(-50%);
    width: 25px;
    height: 25px;
    background: white;
    border-radius: 50%;
    border: 3px solid #3D6E2E;
    outline: 3px solid white;
    transition: left 0.3s ease-in-out;
  }

  .size-label {
    display: inline-block;
    font-size: 14px;
    font-weight: bold;
    color: #333;
    margin-top: 5px;
    margin-bottom: -10px;
  }

  .size-label.left {
    float: left;
  }

  .size-label.right {
    float: right;
  }

  .size-label.center {
    position: absolute;
    left: 50%;
    transform: translateX(-50%);
  }
</style>

{% assign raw_handles = product.metafields.custom.complete_the_look %}
{% assign look_handles = raw_handles | replace: '"', '' | replace: '[', '' | replace: ']', '' | split: ',' %}

{% if look_handles.size > 0 and look_handles.first != blank %}
  <div class="get-the-look-box">
    <h3 class="get-the-look-heading">GET THE LOOK</h3>
    <div class="get-the-look-grid" id="get-the-look-grid"></div>
  </div>

 <style>
  .get-the-look-box {
    border: 1px solid #eee;
    padding: 20px;
    border-radius: 8px;
    margin-top: 30px;
  }

  .get-the-look-heading {
    font-weight: 700;
    font-size: 16px;
    margin-bottom: 20px;
  }

  .get-the-look-grid {
    display: flex;
    flex-wrap: wrap;
    gap: 16px;
    justify-content: center;
  }

  .get-the-look-grid a {
    flex: 0 1 calc(50% - 16px);
    aspect-ratio: 4 / 5;
    border-radius: 6px;
    overflow: hidden;
    transition: transform 0.2s ease;
  }

  .get-the-look-grid a:hover {
    transform: scale(1.02);
  }

  .get-the-look-grid img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    display: block;
  }

</style>



  <script>
    document.addEventListener("DOMContentLoaded", function () {
      const handles = {{ look_handles | json }};
      const grid = document.getElementById("get-the-look-grid");

      handles.forEach(handle => {
        const cleanHandle = handle.trim();
        fetch(`/products/${cleanHandle}.js`)
          .then(response => {
            if (!response.ok) {
              console.error(`Failed to load product for handle: ${cleanHandle}`);
              return null;
            }
            return response.json();
          })
          .then(product => {
            if (!product || !product.images || product.images.length === 0) {
              console.warn("No images found for product:", product);
              return;
            }
            const img = product.images[0];
            const link = document.createElement("a");
            link.href = product.url;
            link.innerHTML = `<img src="${img}" alt="${product.title}" />`;
            grid.appendChild(link);
          })
          .catch(err => console.error("Fetch error:", err));
      });
    });
  </script>
{% endif %}
